INSERT INTO service VALUES('ef912a9e3bdc7089203c25c6aeba48faa1088f8b48f75a33267da0f369b3838f','https://www.bmbfsfj.bund.de/','bmfsfj.de',NULL,NULL,'Kinderzuschlag, Familienleistungen, Unterstützung',NULL,NULL,'Kinderzuschlag,Familienleistungen,Unterstützung','de','<!DOCTYPE html> <html lang="de" dir="ltr" > <head> <meta charset="UTF-8"/> <title> Startseite - BMBFSFJ </title> <meta http-equiv="X-UA-Compatible" content="IE=Edge"/> <!-- Viewport mobile tag for sensible mobile support --> <meta name="viewport" content="width=device-width, initial-scale=1"> <meta name="robots" content="index,follow"/> <link rel="icon" href="/resource/blob/39278/ceb1efdb73e673031b74b427d1f11405/bmbfsfj-homepage-favicon.ico"> <link rel="shortcut icon" type="image/x-icon" href="/resource/blob/39278/ceb1efdb73e673031b74b427d1f11405/bmbfsfj-homepage-favicon.ico"/> <meta name="apple-mobile-web-app-title" content="BMBFSFJ"> <meta name="application-name" content="BMBFSFJ"> <link rel="stylesheet" href="/resource/themes/rebrush/css/rebrush-181260-89.css" > <script src="/resource/themes/rebrush/js/commons-181252-29.js" defer="false" ></script><script src="/resource/themes/rebrush/js/rebrush-181256-80.js" defer="false" ></script><meta name="description" content="Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."/><script type="text/javascript"> window.doTrack = true; </script> <script type="text/javascript"> const matomoTags = [ ]; // initMatomoTags window.initMatomoTags = () => { const _mtm = window._mtm = window._mtm || []; _mtm.push({''mtm.startTime'': (new Date().getTime()), ''event'': ''mtm.Start''}); const d = document; matomoTags.forEach(tag => { const g = d.createElement(''script''); const s = d.getElementsByTagName(''script'')[0]; g.async = true; g.src = ''https://analytics.init.de/js/container_'' + tag + ''.js''; s.parentNode.insertBefore(g, s); }); }; // initMatomo window.initMatomo = () => { console.info(">> Init Matomo"); // check of cookie banner schon beantwortet var _paq = window._paq = window._paq || []; _paq.push([''disableCookies'']); _paq.push([''enableLinkTracking'']); _paq.push([''trackPageView'']); (function () { var u = "https://analytics.init.de/"; _paq.push([''setTrackerUrl'', u + ''matomo.php'']); _paq.push([''setSiteId'', ''35'']); var d = document, g = d.createElement(''script''), s = d.getElementsByTagName(''script'')[0]; g.type = ''text/javascript''; g.async = true; g.src = u + ''matomo.js''; s.parentNode.insertBefore(g, s); })(); if (matomoTags.length > 0) { window.initMatomoTags(); } } const allowCookie = document.cookie.split(";").find((cookie) => cookie.includes("cookie-allow-tracking")); if (allowCookie && allowCookie.split("=")[1] === "1") { window.initMatomo(); } </script><meta name="twitter:card" content="summary_large_image"> <meta name="twitter:site" content="@bmfsfj"> <meta name="twitter:title" content="BMBFSFJ"> <meta name="twitter:description" content="Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."> <meta name="twitter:image" content="https://www.bmbfsfj.bund.de/resource/blob/270414/4fc62becabe162356842e8befc2e9f84/20250916-karin-prien-startet-bell-neu-data.jpg"> <meta name="twitter:image:alt" content="Karin Prien überreicht Fördergeld für Bildungsangebote für ältere Menschen"><meta property="og:title" content="BMBFSFJ"> <meta property="og:description" content="Hier finden Sie aktuelle Informationen des Bundesministeriums für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ)."> <meta property="og:url" content="https://www.bmbfsfj.bund.de/bmbfsfj"> <meta property="og:type" content="website"> <meta property="og:site_name" content="BMBFSFJ"> <meta property="og:image" content="https://www.bmbfsfj.bund.de/resource/blob/270414/4fc62becabe162356842e8befc2e9f84/20250916-karin-prien-startet-bell-neu-data.jpg"> <meta property="og:image:alt" content="Karin Prien überreicht Fördergeld für Bildungsangebote für ältere Menschen"> </head> <body> <div class="cookie-banner" aria-hidden="true" role="dialog" aria-modal="true" aria-labelledby="cookie-title" aria-describedby="cookie-description"> <div class="container"> <p id="cookie-title" class="sr-only">Cookie-Einstellungen</p> <div class="cookie-banner__intro-wrapper"> <div id="cookie-description" class="cookie-banner__intro-col"> <p>Mit der Einwilligung von Nutzenden dieser Webseite verwendet das BMBFSFJ (Verantwortlicher) ein Webverhalten- Analysetool (Matomo), um das Angebot auf dieser Webseite kontinuierlich zu verbessern. Dieses Skript ermöglicht die Speicherung bzw. den Zugriff auf die Endeinrichtung. Die verarbeiteten Daten werden nach 90 Tagen gelöscht. Nach Erteilung der Einwilligung oder Ablehnung wird das Banner für 365 Tage deaktiviert. </p><p>Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. </p> </div> <div class="cookie-banner-buttons"> <div class="cookie-banner__btn-wrapper"> <button class="cookie-banner__btn cookie-banner__btn--all" type="button"> Einwilligen </button> </div> <div class="cookie-banner__btn-wrapper"> <button class="cookie-banner__btn cookie-banner__btn--close" type="button"> Ablehnen </button> </div> </div> </div> <div class="cookie-banner__text"> <div class="cookie-banner__toggledown"> <button class="cookie-banner__toggledown-title" aria-controls="cookie-banner__toggledown" data-slide-toggle-target-class="js-collapsible-cookie"> Mehr Informationen </button> <div class="cookie-banner__toggledown-item js-collapsible-cookie" id="cookie-banner__toggledown" data-slide-toggle-target-closed> <p><strong>Verarbeitete Daten:</strong></p><ul class="rte--list"><li>IP-Adresse,</li><li>Gerätetyp, Gerätemarke, Gerätemodell,</li><li>Betriebssystem-Version,</li><li>Browser/Browser-Engines und Browser-Plugins,</li><li>aufgerufene URLs,</li><li>die Website, von der auf die aufgerufene Seite gelangt wurde (Referrer-Site),</li><li>Verweildauer,</li><li>heruntergeladene PDFs,</li><li>eingegebene Suchbegriffe.<br/> </li></ul><p><strong>Technologie</strong></p><p>Eingesetzt wird ein Tool, dass das Webverhalten analysiert (Matomo). Auf Basis der gesammelten Daten wird das Navigationsverhalten von Nutzenden erkannt und analysiert. Mit der Einbindung und der Auslieferung eines Skriptes (matomo.js) werden durch den Dienst Informationen auf der Einrichtung des Nutzenden gespeichert bzw. auf Informationen zugegriffen, die bereits in der Endeinrichtung gespeichert waren. </p><p><strong>Zweck der Verarbeitung</strong></p><p>Zweck der Datenverarbeitung ist die Verbesserung der Struktur und Gestaltung des Webseitenangebotes.</p><p><strong>Rechtsgrundlage</strong></p><p>Rechtsgrundlage der Verarbeitung ist die Einwilligung nach Art. 6 Abs. 1 Buchstabe a) Datenschutz-Grundverordnung (DSGVO) in Verbindung mit § 25 Abs. 1 Telekommunikation-Digitale-Dienste-Datenschutz-Gesetz (TDDDG). </p><p>Ein Widerruf der Einwilligung ist jederzeit möglich, die Rechtmäßigkeit der Verarbeitung bleibt bis zum Zeitpunkt des Widerrufs unberührt. Die Möglichkeit des Widerrufs der Einwilligung erscheint oben auf der Webseite, wenn Sie auf die Datenschutzerklärungen klicken. </p><p><strong>Speicherdauer</strong></p><p>Die Daten werden umgehend pseudonymisiert und nach 90 Tagen gelöscht.</p><p><strong>Weitere Informationen:</strong></p><p>Weitere Informationen zur Verarbeitung personenbezogener Daten finden sich in den <a href="/bmbfsfj/informationen-zur-verarbeitung-personenbezogener-daten-99428" target="_self"><u>Datenschutzhinweisen</u></a>.</p> </div> </div> </div> </div> </div> <div class="wrapper"> <header class="header"> <div class="container header__grid-container"> <div class="skiplinks" id="top" tabindex="-1"> <span class="sr-only">Direktlink:</span> <ul class="skiplinkWrapper skiplinkWrapper__mobile"> <li><a href="#inhalt">Inhalt</a></li> <li><a href="#mobile-nav-menu">Hauptnavigation</a></li> </ul> <ul class="skiplinkWrapper skiplinkWrapper__desktop"> <li><a href="#inhalt">Inhalt</a></li> <li><a href="#main-navigation">Hauptnavigation</a></li> <li><a href="#footernavigation">Footernavigation</a></li> </ul> </div> <div class="mobile-header"> <div class="header__logo header__logo--subdivision"> <img src="/resource/crblob/225204/be88fd51f4444c5407aaf1ae0e54939c/logo-bmfsfj-weisser-hintergrund-data.svg" alt="Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ) – zur Startseite"/> </div> <div class="header__search-toggle"> <button class="header__search-button" type="button" aria-controls="header__search-form" aria-expanded="false"> <span class="header__search-button-label sr-only-mobile-wide">Suche</span> <span class="icon icon_search" aria-hidden="true"></span> </button> </div> <div class="mobile-header-menu"> <button id="mobile-nav-menu" class="mobile-nav-menu mobile-nav-menu-bmfsfj" aria-label="Hauptnavigation" aria-expanded="false" aria-controls="main-navigation"> <span class="menu-bar" aria-hidden="true"></span> <span class="sr-only">Navigation öffnen/schließen</span> </button> </div> </div> <div class="header__grid-cell header__grid-cell-1"> <div id="logo" class="header__logo header__logo--subdivision"> <img src="/resource/crblob/225204/be88fd51f4444c5407aaf1ae0e54939c/logo-bmfsfj-weisser-hintergrund-data.svg" alt="Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend (BMBFSFJ) – zur Startseite"/> </div> <div class="header__logo--sticky header__logo--subdivision--small"> <img src="/resource/crblob/226130/fef90aeb91987da9f5c00cffac7caa3f/logo-bmfsfj-responsiv-data.svg" alt="Bundesministerium für Bildung, Familie, Senioren, Frauen und Jugend (BMFSFJ) – zur Startseite"/> </div> </div> <div class="header__grid-cell header__grid-cell-2"> <nav class="header__servicenavigation" aria-label="Meta Navigation"> <ul class="header__servicenavigation__list"> <li class="header__servicenavigation__list-item"> <a href=